import { mergeBbox } from "../geometry/boundingBoxUtils.js";
/** A simple bounding box defined by 4 coordinates: xMin, yMin, xMax, yMax */
export class BBox {
    constructor(xMin, yMin, xMax, yMax) {
        this.xMin = xMin;
        this.yMin = yMin;
        this.xMax = xMax;
        this.yMax = yMax;
    }
    mergeBbox(bbox) {
        return mergeBbox(this, bbox);
    }
}
